let documentId = null;
let formattedTheme = null;
let summaries = null;

/**
 * Recursively walk the entire object tree
 * and collect document, formatted_theme, and summaries
 */
function walk(obj) {
  if (!obj || typeof obj !== 'object') return;

  if (obj.document && !documentId) {
    documentId = obj.document;
  }

  if (obj.formatted_theme && !formattedTheme) {
    formattedTheme = obj.formatted_theme;
  }

  if (obj.summaries && !summaries) {
    summaries = obj.summaries;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    if (Array.isArray(value)) {
      value.forEach(walk);
    } else if (typeof value === 'object') {
      walk(value);
    }
  }
}

// 1. Workflow Initiated path
try {
  const items = $('Workflow Initiated').all();
  if (items.length > 0) {
    walk(items[0].json);
  }
} catch (e) {
  console.error('Workflow Initiated error:', e);
}

// 2. Chat-trigger fallback
if (!documentId || !formattedTheme || !summaries) {
  try {
    const chatInput = $('When chat message received').first().json.chatInput;
    if (chatInput) {
      const parsed = JSON.parse(chatInput);
      walk(parsed);
    }
  } catch (e) {
    console.error('Chat-trigger error:', e);
  }
}

// 3. Guards
if (!documentId) {
  throw new Error('Document ID not found in any input');
}

if (!formattedTheme) {
  throw new Error('formatted_theme not found in any input');
}

if (!summaries) {
  throw new Error('summaries not found in any input');
}

// 4. Output
return [
  {
    json: {
      inputData: documentId,
      formatted_theme: formattedTheme,
      summaries: summaries
    }
  }
];

// Extract the DYK and IT posts from the first input
const rawText = $('Generate Social media post using LLM').first().json.output.data;

// Regex patterns to find titles
const dykPattern = /\*DYK #(\d+) — (.+?)\*/g;
const itPattern = /\*IT #(\d+) — (.+?)\*/g;

// Build DYK options
const dykOptions = [...rawText.matchAll(dykPattern)].map(match => ({
  option: `DYK #${match[1]} — ${match[2]}`
}));

// Build IT options
const itOptions = [...rawText.matchAll(itPattern)].map(match => ({
  option: `IT #${match[1]} — ${match[2]}`
}));

// Combine options into a single list
const allOptions = [...dykOptions, ...itOptions];

// Build the Slack-style form for n8n
$input.first().json.approve_form = [
  {
    fieldLabel: "Select DYK & IT Posts for Captioning",
    fieldType: "checkbox",
    fieldOptions: {
      values: allOptions
    }
  }
];

return $input.all();

// Phase 1 output JSON (from your Fetch node)
const phase1OutputRaw = $('Generate Social media post using LLM').first().json.output.data;

// Selected posts array (from your Select node)
const selectedPostTitles = $input.first().json.data["Select DYK & IT Posts for Captioning"];

// Formatted theme object (from your workflow input)
const formattedTheme = $('Fetch HTML Document ID').first().json.formatted_theme;

// Helper function to split the Phase 1 raw string into individual posts
function extractPosts(rawText) {
    const posts = rawText.split('–––––––––––––––––').map(p => p.trim()).filter(Boolean);
    return posts;
}

// Helper to get source URL from formatted_theme
function getSourceUrl(sourceString) {
    if (!sourceString) return "";

    const sourceKey = sourceString.split(" - ")[0].trim(); // e.g., "Main Article 1" or "FEATURED ARTICLE"
    const sourceNumber = sourceString.match(/\d+/)?.[0];  // e.g., "3"

    for (const key in formattedTheme) {
        const item = formattedTheme[key];

        if (!item) continue;

        // Match by key name
        if (key.toUpperCase() === sourceKey.toUpperCase()) {
            return item.URL || "";
        }

        // Match by Source number
        if (sourceNumber && item.Source === sourceNumber) {
            return item.URL || "";
        }
    }

    return "";
}


// Extract all individual posts
const allPosts = extractPosts(phase1OutputRaw);

// Filter posts by selected titles
const filteredPosts = allPosts.filter(post => {
    return selectedPostTitles.some(title => post.includes(title));
});

// Map filtered posts into structured objects
const structuredPosts = filteredPosts.map(postText => {
    // Original title (DYK #X or IT #X)
    const titleMatch = postText.match(/^\*?(DYK|IT) #[\d]+ — (.+?)\*/m);
    const title = titleMatch ? titleMatch[0].replace(/\*/g, "") : "";

    // Original headline
    const originalHeadline = titleMatch ? titleMatch[2] : "";

    // Source
    const sourceMatch = postText.match(/\*Source\*: (.+)/m);
    const source = sourceMatch ? sourceMatch[1] : "";

    // Source URL from formatted_theme
    const sourceUrl = getSourceUrl(source);

    // Graphic Component info
    const graphicMatch = postText.match(/\*Graphic Component\* \((.+)\)/m);
    const graphicComponentInfo = graphicMatch ? graphicMatch[1] : "";

    // Emphasis Recommendation
    const emphasisMatch = postText.match(/\*Emphasis Recommendation\*: (.+)/m);
    const emphasis = emphasisMatch ? emphasisMatch[1] : "";

    // Full graphic text
    const graphicTextMatch = postText.match(/(Did You Know\?|\\*Inside Tip:\\*)([\s\S]+)/m);
    const graphicText = graphicTextMatch ? graphicTextMatch[2].trim() : "";

    return {
            title,
            originalHeadline,
            source,
            sourceUrl,        // <-- added source URL here
            graphicComponentInfo,
            emphasis,
            graphicText
    };
});

return {
  posts: structuredPosts
};

// Try to get rawText from Re-Generate, fallback to Generate
let rawText = '';
try {
    const regenNode = $('Re-Generate post captions using LLM').first();
    if (regenNode?.json?.output?.data) {
        rawText = regenNode.json.output.data;
    } else {
        throw new Error('Re-Generate node empty, fallback to Generate');
    }
} catch (e) {
    // fallback to original Generate node
    const genNode = $('Generate post captions using LLM').first();
    rawText = genNode?.json?.output?.data || '';
}

// Regex patterns to find titles (adjusted for colon and asterisks)
const dykPattern = /\*DYK #(\d+):\* \*(.+?)\*/g;
const itPattern = /\*IT #(\d+):\* \*(.+?)\*/g;

// Build DYK options
const dykOptions = [...rawText.matchAll(dykPattern)].map(match => ({
  option: `DYK #${match[1]} — ${match[2]}`
}));

// Build IT options
const itOptions = [...rawText.matchAll(itPattern)].map(match => ({
  option: `IT #${match[1]} — ${match[2]}`
}));

// Combine options into a single list
const allOptions = [...dykOptions, ...itOptions];

// Build the Slack-style form for n8n
$input.first().json.approve_form = [
  {
    fieldLabel: "Select DYK & IT Posts to create final artifact",
    fieldType: "checkbox",
    fieldOptions: {
      values: allOptions
    }
  }
];

return $input.all();

// Fetch the formatted_theme from your HTML document node
const formattedTheme = $('Fetch HTML Document ID').first().json.formatted_theme;

// Fetch the newsletter HTML content from the input node
const content = $input.first().json.content;

// Combine into a single object
return {
  json: {
    newsletter: {
      formattedTheme,
      content
    }
  }
};

// Selected posts from user input
const selectedPosts = $input.first().json.data["Select DYK & IT Posts to create final artifact"];

// Full output with all posts
let allPostsRaw = '';
try {
    const regenNode = $('Re-Generate post captions using LLM').first();
    if (regenNode?.json?.output?.data) {
        allPostsRaw = regenNode.json.output.data;
    } else {
        throw new Error('Re-Generate node empty, fallback to Generate');
    }
} catch (e) {
    // fallback to original Generate node
    const genNode = $('Generate post captions using LLM').first();
    allPostsRaw = genNode?.json?.output?.data || '';
}


// Split full output into individual posts by separator '---'
const allPostsArray = allPostsRaw.split('---').map(p => p.trim()).filter(p => p);

// Filter and combine selected posts into a single blob
const combinedBlob = allPostsArray
    .map(post => {
        // Extract the post title, e.g., "DYK #1 — AI Governance ROI"
        const titleMatch = post.match(/\*(DYK|IT) #\d+:?\*\s\*(.+?)\*/);
        if (!titleMatch) return null;

        const type = titleMatch[1];       // DYK or IT
        const headline = titleMatch[2];   // e.g., AI Governance ROI
        const postIdentifier = `${type} #${titleMatch[0].match(/\d+/)[0]} — ${headline}`;

        if (!selectedPosts.includes(postIdentifier)) return null;

        return post; // keep full post content
    })
    .filter(p => p !== null)
    .join('\n\n---\n\n'); // merge into single blob with separators

return {
    json: {
        newsletterBlob: combinedBlob
    }
};
